import utc from 'dayjs/plugin/utc';
import timezone from 'dayjs/plugin/timezone';
import duration from 'dayjs/plugin/duration';
import dayjs, { OpUnitType } from 'dayjs';
import {
    DEFAULT_EMPTY_VALUE,
    DEFAULT_TIMEZONE,
    TIME_SECOND_FORMAT,
    TIME_DAY_FORMAT,
    TIME_DAY_WITH_WEEK_FORMAT
} from '../const';
import { IdentifierType } from '../type';

dayjs.extend(utc);
// 用于计算ms转换min，hour，day
dayjs.extend(duration);
dayjs.extend(timezone);

/**
 * 时区时间
 * @param localTime required 本地时间字符串 或 unix 时间戳
 * @param tz optional 转换目标时区，默认值为平台默认时区 DEFAULT_TIMEZONE，
 * @param keepLocalTime optional 是否保持本地时间，默认值为 false, 如果为 true，则 tz 不生效
 */
export function tzTime(
    localTime?: Parameters<typeof dayjs>[0],
    tz = DEFAULT_TIMEZONE,
    keepLocalTime = false
) {
    return dayjs(localTime).tz(tz, keepLocalTime);
}

/**
 * 本地时间转其他时区格式化工具
 * @param localTime required 本地时间字符串 或 unix 时间戳
 * @param format optional 时间格式，默认值为 YYYY-MM-DD HH:mm:ss
 * @param tz optional 转换目标时区，默认值为平台默认时区 DEFAULT_TIMEZONE，
 */
export function tzTimeFormatter(
    localTime: Parameters<typeof dayjs>[0],
    format = TIME_SECOND_FORMAT,
    tz = DEFAULT_TIMEZONE
) {
    return localTime ? tzTime(localTime, tz, false).format(format) : DEFAULT_EMPTY_VALUE;
}

/**
 * 任意时区时间转换时间戳
 * @description
 * @param sourceTime required 源时间
 * @param operator 操作
 * @param unit 单位
 * @param tz 时区，默认为平台默认时间
 * @param keepLocalTime 是否保持本地时间，默认值 true
 */
export const toTzTimestamp = (
    sourceTime: Parameters<typeof dayjs>[0],
    operator: 'startOf' | 'endOf',
    unit: OpUnitType,
    tz = DEFAULT_TIMEZONE,
    keepLocalTime = true
) => (sourceTime ? tzTime(sourceTime, tz, keepLocalTime)[operator](unit).valueOf() : undefined);

/**
 * 指定时区对应的 timestamp range 对象的转换工具
 * @param fields required 最终生成对象的字段，数量会影响最终返回的数据结构
 * @param unit optional 单位, 默认值为 'd'
 * @param tz 时区，默认为平台默认时间
 */
export const tzTimestampRangeTransformer =
    (fields: [string, string?], unit = 'd' as OpUnitType, tz = DEFAULT_TIMEZONE) =>
    (timeRange: [Parameters<typeof dayjs>[0], Parameters<typeof dayjs>[0]]) => {
        if (!timeRange) return {};
        const startTime = toTzTimestamp(timeRange[0], 'startOf', unit, tz);
        const endTime = toTzTimestamp(timeRange[1], 'endOf', unit, tz);
        if (fields.length > 1) {
            return {
                [fields[0]]: startTime,
                [fields[1] as string]: endTime
            };
        }
        return { [fields[0]]: [startTime, endTime] };
    };

/**
 * 日期的格式化，后续改成formatDate
 * @param {*} val
 */
export const formatTime = (val: any) => tzTimeFormatter(val, TIME_DAY_FORMAT);

/**
 * 日期的格式化
 * @param {*} val
 */
export const formatDate = (val: any) => tzTimeFormatter(val, TIME_DAY_FORMAT);

/**
 * 日期带周的格式化
 * @param {*} val
 */
export const formatDateWithWeek = (val: any) => tzTimeFormatter(val, TIME_DAY_WITH_WEEK_FORMAT);

/**
 * 导出时间的校验
 * @param {IdentifierType} [start]
 * @param {IdentifierType} [end]
 * @param {{ ignoreEmpty?: boolean; max?: number }} [opt]
 */
export const checkExportTime = (
    start?: IdentifierType,
    end?: IdentifierType,
    opt?: { ignoreEmpty?: boolean; max?: number }
) =>
    (opt?.ignoreEmpty || (!!start && !!end)) &&
    dayjs(end).diff(dayjs(start), 'day') <= (opt?.max ?? 31);

/**
 * 多个导出时间的校验
 * @param {Parameters<typeof checkExportTime>[]} arr
 * @param {number} [max=31]
 */
export const checkAllExportTime = (arr: Parameters<typeof checkExportTime>[], max = 31) =>
    arr.some((timeRange) => checkExportTime(timeRange?.[0], timeRange?.[1], { max }));
